```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TokenVoting {
    address public owner;
    uint256[] private _candidateIds;
    string[] private _candidateNames;
    mapping(uint256 => uint256) private _candidateVotes;
    mapping(address => mapping(uint256 => bool)) private _voted;
    mapping(address => bool) private _voters;

    event CandidateAdded(uint256 indexed id, string name);
    event VotingRightsGranted(address indexed voter);
    event Voted(uint256 indexed candidateId, address indexed voter);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    function candidateCount() public view returns (uint256) {
        return _candidateIds.length;
    }

    function candidateNames(uint256 index) public view returns (string memory) {
        require(index < _candidateIds.length, "Invalid index");
        return _candidateNames[index];
    }

    function candidateVotes(uint256 candidateId) public view returns (uint256) {
        require(candidateId < _candidateIds.length, "Invalid candidate id");
        return _candidateVotes[candidateId];
    }

    function addCandidate(string memory name) public onlyOwner {
        uint256 id = _candidateIds.length;
        _candidateIds.push(id);
        _candidateNames.push(name);
        emit CandidateAdded(id, name);
    }

    function grantVotingRights(address voter) public onlyOwner {
        require(!_voters[voter], "Voting rights already granted");
        _voters[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return _voters[voter];
    }

    function vote(uint256 candidateId) public {
        bool hasRights = hasVotingRights(msg.sender);
        bool isValidId = candidateId < _candidateIds.length;
        bool alreadyVoted = _voted[msg.sender][candidateId];

        require(hasRights, "No voting rights");
        require(isValidId, "Invalid candidate id");
        require(!alreadyVoted, "Already voted");

        _voted[msg.sender][candidateId] = true;
        _candidateVotes[candidateId]++;
        emit Voted(candidateId, msg.sender);
    }

    // Optional: Ownership transfer mechanism for future flexibility
    address private _newOwner;
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "Invalid new owner address");
        _newOwner = newOwner;
    }

    function acceptOwnership() public {
        require(msg.sender == _newOwner, "Only the new owner can accept ownership");
        emit OwnershipTransferred(owner, msg.sender);
        owner = msg.sender;
        _newOwner = address(0);
    }
}
```

